import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const MALE_CATEGORIES = [
  { label: "Essential Fat", max: 5, color: "from-blue-500 to-blue-700" },
  { label: "Athletes", max: 13, color: "from-emerald-500 to-emerald-700" },
  { label: "Fitness", max: 17, color: "from-teal-500 to-teal-700" },
  { label: "Average", max: 24, color: "from-amber-500 to-amber-700" },
  { label: "Obese", max: Infinity, color: "from-red-500 to-red-700" },
];
const FEMALE_CATEGORIES = [
  { label: "Essential Fat", max: 13, color: "from-blue-500 to-blue-700" },
  { label: "Athletes", max: 20, color: "from-emerald-500 to-emerald-700" },
  { label: "Fitness", max: 24, color: "from-teal-500 to-teal-700" },
  { label: "Average", max: 31, color: "from-amber-500 to-amber-700" },
  { label: "Obese", max: Infinity, color: "from-red-500 to-red-700" },
];

const FAQS = [
  { q: "How is body fat percentage calculated using the Navy method?", a: "The US Navy method uses waist, neck, and hip (women only) circumference measurements along with height. It's considered reasonably accurate for most people and is widely used as a non-invasive estimation method." },
  { q: "What is a healthy body fat percentage?", a: "For men: essential fat 2-5%, athletes 6-13%, fitness 14-17%, average 18-24%, obese 25%+. For women: essential 10-13%, athletes 14-20%, fitness 21-24%, average 25-31%, obese 32%+." },
  { q: "How accurate are body fat estimation methods?", a: "All non-invasive methods have error ranges. DEXA scans are most accurate (-. Hydrostatic weighing - Skinfold calipers - Navy method - Bioelectrical impedance -" },
  { q: "What is lean body mass?", a: "Lean body mass (LBM) is your total body weight minus fat weight. It includes muscles, bones, organs, and water. LBM is important for calculating protein needs and is a better indicator of fitness than total weight." },
  { q: "Where do I measure my waist for body fat?", a: "Measure your waist at the narrowest point - typically just above the navel and below the ribcage. Do not suck in your stomach. Breathe normally and measure at the end of a normal exhale." },
  { q: "Where do I measure my hips for body fat (women)?", a: "Measure your hips at the widest point - usually around the fullest part of your buttocks. Stand with feet together and measure horizontally around the widest part." },
  { q: "Can I reduce body fat percentage without losing weight?", a: "Yes - by gaining muscle while losing fat (body recomposition). The scale may stay the same or even increase slightly while your body fat percentage drops. This is common when starting a strength training program." },
];

export default function BodyFatCalculator() {
  const [gender, setGender] = useState<"male" | "female">("male");
  const [heightCm, setHeightCm] = useState(175);
  const [weightKg, setWeightKg] = useState(80);
  const [waistCm, setWaistCm] = useState(85);
  const [neckCm, setNeckCm] = useState(38);
  const [hipCm, setHipCm] = useState(95);

  const circumferenceTerm = gender === "male" ? waistCm - neckCm : waistCm + hipCm - neckCm;
  const safeCircumferenceTerm = Math.max(1, circumferenceTerm);
  const safeHeightCm = Math.max(1, heightCm);

  const bodyFat = gender === "male"
    ? 495 / (1.0324 - 0.19077 * Math.log10(safeCircumferenceTerm) + 0.15456 * Math.log10(safeHeightCm)) - 450
    : 495 / (1.29579 - 0.35004 * Math.log10(safeCircumferenceTerm) + 0.221 * Math.log10(safeHeightCm)) - 450;

  const clampedBF = Math.max(1, Math.min(60, bodyFat));
  const fatMassKg = weightKg * (clampedBF / 100);
  const leanMassKg = weightKg - fatMassKg;

  const categories = gender === "male" ? MALE_CATEGORIES : FEMALE_CATEGORIES;
  const catIdx = categories.findIndex(c => clampedBF <= c.max);
  const category = categories[catIdx === -1 ? categories.length - 1 : catIdx];

  return (
    <>
      <SEOHead
        title="Free Body Fat Calculator Online - Estimate Body Fat Percentage Instantly | CalcHive"
        description="Free online body fat calculator. Estimate your body fat percentage using the US Navy circumference method instantly. 100% free for everyone, no signup required."
        canonical="/body-fat-calculator"
        keywords="free body fat calculator, body fat percentage calculator free online, US navy body fat calculator free, calculate body fat free, free body fat estimator"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Body Fat Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free body fat calculator to calculate body fat free with the US Navy circumference method. This body fat percentage calculator free online works as a US navy body fat calculator free and free body fat estimator for men and women.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex gap-2 mb-6">
            {(["male", "female"] as const).map(g => (
              <button key={g} onClick={() => setGender(g)} className={`px-4 py-1.5 rounded-full text-sm font-semibold border capitalize transition-all ${gender === g ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>{g}</button>
            ))}
          </div>
          <div className="space-y-6 mb-8">
            <SliderInput id="height-bf" label="Height" value={heightCm} min={91.44} max={243.84} step={0.1} onChange={setHeightCm} format={v => `${v} cm`} testId="input-height" />
            <SliderInput id="weight-bf" label="Weight" value={weightKg} min={30} max={635} step={0.1} onChange={setWeightKg} format={v => `${v} kg`} testId="input-weight" />
            <SliderInput id="waist-bf" label="Waist (at narrowest)" value={waistCm} min={40} max={200} step={0.5} onChange={setWaistCm} format={v => `${v} cm`} testId="input-waist" />
            <SliderInput id="neck-bf" label="Neck (at narrowest)" value={neckCm} min={25} max={70} step={0.5} onChange={setNeckCm} format={v => `${v} cm`} testId="input-neck" />
            {gender === "female" && <SliderInput id="hip-bf" label="Hips (at widest)" value={hipCm} min={60} max={180} step={0.5} onChange={setHipCm} format={v => `${v} cm`} testId="input-hip" />}
          </div>
          <motion.div key={`${gender}-${heightCm}-${weightKg}-${waistCm}-${neckCm}-${hipCm}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${category.color} rounded-2xl p-6 mb-4 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Body Fat Percentage</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-bf">{clampedBF.toFixed(1)}%</p>
              <p className="text-white/70 text-sm mt-1">{category.label}</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[{ label: "Fat Mass", value: `${fatMassKg.toFixed(1)} kg`, red: true }, { label: "Lean Mass", value: `${leanMassKg.toFixed(1)} kg`, green: true }, { label: "Category", value: category.label }].map(({ label, value, red, green }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-lg font-extrabold ${red ? "text-red-600 dark:text-red-400" : green ? "text-emerald-600 dark:text-emerald-400" : "text-foreground"}`}>{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <MedicalDisclaimer /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Body Fat Percentage for Free</h2>
          <p className="text-muted-foreground leading-relaxed">The US Navy circumference method was developed by Hodgdon and Beckett in 1984 as a practical field test for military fitness assessments. It uses body circumference measurements as a proxy for fat distribution, producing results comparable to skinfold calipers without specialized equipment.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-3">
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Male Formula</p>
              <p>BF% = 86.010  x  log-waist - neck) - 70.041  x  log-height) + 36.76</p>
            </div>
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Female Formula</p>
              <p>BF% = 163.205  x  log-waist + hip - neck) - 97.684  x  log-height) - 78.387</p>
            </div>
            <p className="text-xs text-muted-foreground">All measurements in inches</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">What is the US Navy Body Fat Method</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Category", "Men", "Women", "Description"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Essential Fat", "2-5%", "10-13%", "Minimum fat for organ function"],
                  ["Athletes", "6-13%", "14-20%", "Competitive sports performance range"],
                  ["Fitness", "14-17%", "21-24%", "Fit and healthy, active lifestyle"],
                  ["Average", "18-24%", "25-31%", "Typical healthy adult range"],
                  ["Obese", "25%+", "32%+", "Elevated health risk, action recommended"],
                ].map(([cat, men, women, desc]) => (
                  <tr key={cat} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{cat}</td>
                    <td className="py-2.5 px-4 text-blue-600 dark:text-blue-400 font-medium">{men}</td>
                    <td className="py-2.5 px-4 text-pink-600 dark:text-pink-400 font-medium">{women}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{desc}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Body Fat Estimator for Men and Women</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Method", "Accuracy", "Cost", "Availability"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["DEXA Scan", "+/- 1-2%", "$50-$150", "Medical facilities"],
                  ["Hydrostatic Weighing", "+/- 2-3%", "$50-$100", "University/research labs"],
                  ["BodPod (Air Displacement)", "+/- 2-3%", "$45-$100", "Some gyms and universities"],
                  ["Skinfold Calipers", "+/- 3-5%", "$5-$30 (calipers)", "Gyms, personal trainers"],
                  ["US Navy Method (this tool)", "+/- 3-4%", "Free", "Anywhere with a tape measure"],
                  ["Bioelectrical Impedance (BIA)", "+/- 4-8%", "$30-$200 (scale)", "Home scales, gyms"],
                ].map(([method, acc, cost, avail]) => (
                  <tr key={method} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{method}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{acc}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{cost}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{avail}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h3 className="text-2xl font-bold text-foreground">How to Reduce Body Fat Percentage</h3>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li><strong className="text-foreground">Create a caloric deficit.</strong> Eating 300-500 calories below your TDEE (Total Daily Energy Expenditure) promotes fat loss without excessive muscle loss.</li>
            <li><strong className="text-foreground">Prioritize protein.</strong> Eating 0.7-1g protein per pound of bodyweight preserves lean mass during a calorie deficit, improving your body fat percentage even if total weight loss is modest.</li>
            <li><strong className="text-foreground">Strength train 3-4 times per week.</strong> Building muscle increases your resting metabolic rate and directly improves your lean-mass-to-fat-mass ratio.</li>
            <li><strong className="text-foreground">Sleep 7-9 hours per night.</strong> Poor sleep increases cortisol (a fat-storage hormone) and impairs muscle recovery and fat burning.</li>
            <li><strong className="text-foreground">Track progress monthly, not daily.</strong> Body fat percentage changes slowly - re-measure every 4-6 weeks for meaningful data.</li>
          </ul>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/body-fat-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


